                  >
                    <ShoppingBag className="w-4 h-4 text-white" />
                    <span className="font-black text-[9px] md:text-xs text-white uppercase tracking-widest">Browse Goods</span>
                  </button>
              </div>
            )}

            {!isLocalTutorialStep && (
              <DialogueBox 
                speaker="Garrick"
                text={dialogue}
                className="w-full relative pointer-events-auto"
              />
