import { EquipmentItem } from '../types/inventory';
import { Equipment, EquipmentRarity, EquipmentType, EquipmentStats } from '../models/Equipment';
import { MASTERY_THRESHOLDS } from '../config/mastery-config';

const mapSubCategoryToType = (subCat: string): EquipmentType => {
    return subCat as EquipmentType; 
};

/**
 * 상향 조정된 레벨별 누적 경험치 테이블
 * 아이템 품질(약 100)이 그대로 경험치가 되므로 요구량을 대폭 늘림
 */
export const LEVEL_EXP_TABLE = [
    0,      // Lv 1
    500,    // Lv 2 (약 5번 제작)
    1200,   // Lv 3
    2200,   // Lv 4
    3500,   // Lv 5 (Tier 2 Unlock)
    5200,   // Lv 6
    7500,   // Lv 7
    10500,  // Lv 8
    14500,  // Lv 9
    20000,  // Lv 10 (Tier 3 Unlock)
    27000,  // Lv 11
    36000,  // Lv 12
    47000,  // Lv 13
    60000,  // Lv 14
    75000,  // Lv 15
    95000   // Lv 16 (Tier 4 Unlock)
];

export function getSmithingLevel(exp: number): number {
  let level = 1;
  for (let i = 0; i < LEVEL_EXP_TABLE.length; i++) {
    if (exp >= LEVEL_EXP_TABLE[i]) level = i + 1;
  }
  return level;
}

export function getUnlockedTier(level: number): number {
  if (level >= 16) return 4;
  if (level >= 10) return 3;
  if (level >= 5) return 2;
  return 1;
}

export function calcCraftExp(args: {
  tier: number;
  quality01: number;      // 0~1 (Internal multiplier, will use quality value instead)
  isQuickCraft: boolean;
  isFirstCraft: boolean;
  quality?: number;       // The actual quality value (0-120)
}): number {
  const { quality = 0, isQuickCraft } = args;

  // 제작된 아이템의 퀄리티를 그대로 경험치로 반환
  // 퀵 크래프트(간이 제작)시에는 효율이 50%로 감소
  const baseExp = quality;
  const quickMult = isQuickCraft ? 0.5 : 1.0;

  return Math.round(baseExp * quickMult);
}

export const getEnergyCost = (item: EquipmentItem, masteryCount: number): number => {
    let cost = 20; 
    if (masteryCount >= MASTERY_THRESHOLDS.ARTISAN) {
        cost -= MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
    }
    return Math.max(5, cost);
};

export const generateEquipment = (recipe: EquipmentItem, quality: number, masteryCount: number, enhancementCount: number = 0): Equipment => {
    let statMultiplier = 1.0;
    let priceMultiplier = 1.0;
    let namePrefix = '';

    if (masteryCount >= MASTERY_THRESHOLDS.ARTISAN) {
        statMultiplier = MASTERY_THRESHOLDS.ARTISAN_BONUS.stats;
        priceMultiplier = MASTERY_THRESHOLDS.ARTISAN_BONUS.price;
        namePrefix = MASTERY_THRESHOLDS.ARTISAN_BONUS.prefix;
    } else if (masteryCount >= MASTERY_THRESHOLDS.ADEPT) {
        statMultiplier = MASTERY_THRESHOLDS.ADEPT_BONUS.stats;
        priceMultiplier = MASTERY_THRESHOLDS.ADEPT_BONUS.price;
        namePrefix = MASTERY_THRESHOLDS.ADEPT_BONUS.prefix;
    }

    const qualityMultiplier = Math.max(0.2, quality / 100); 
    const finalMultiplier = qualityMultiplier * statMultiplier;

    const base = recipe.baseStats || { physicalAttack: 0, physicalDefense: 0, magicalAttack: 0, magicalDefense: 0 };

    const stats: EquipmentStats = {
        physicalAttack: Math.round(base.physicalAttack * finalMultiplier),
        physicalDefense: Math.round(base.physicalDefense * finalMultiplier),
        magicalAttack: Math.round(base.magicalAttack * finalMultiplier),
        magicalDefense: Math.round(base.magicalDefense * finalMultiplier),
    };

    const statKeys: (keyof EquipmentStats)[] = ['physicalAttack', 'physicalDefense', 'magicalAttack', 'magicalDefense'];
    for (let i = 0; i < enhancementCount; i++) {
        const randomKey = statKeys[Math.floor(Math.random() * statKeys.length)];
        stats[randomKey] = Math.round(stats[randomKey] * 1.02);
    }

    const rarityScore = quality + (enhancementCount * 2);

    let rarity = EquipmentRarity.COMMON;
    if (rarityScore >= 125) rarity = EquipmentRarity.LEGENDARY; 
    else if (rarityScore >= 110) rarity = EquipmentRarity.EPIC;  
    else if (rarityScore >= 95) rarity = EquipmentRarity.RARE;
    else if (rarityScore >= 75) rarity = EquipmentRarity.UNCOMMON;

    const price = Math.round(recipe.baseValue * finalMultiplier * priceMultiplier * (1 + enhancementCount * 0.05));

    return {
        id: `${recipe.id}_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
        recipeId: recipe.id,
        name: namePrefix ? `${namePrefix} ${recipe.name}` : recipe.name,
        type: mapSubCategoryToType(recipe.subCategoryId),
        quality: quality,
        rarity: rarity,
        price: price,
        icon: recipe.icon,
        image: recipe.image,
        description: recipe.description,
        stats: stats,
        enhancementCount,
        specialAbilities: [], 
        durability: recipe.maxDurability, 
        maxDurability: recipe.maxDurability,
        isRepairable: recipe.isRepairable,
        equipRequirements: recipe.equipRequirements,
        craftedDate: Date.now(),
        crafterName: 'Lockhart',
        previousOwners: [], 
        slotType: recipe.slotType,
        isTwoHanded: recipe.isTwoHanded
    };
};

import { GameState, InventoryItem } from '../../types/index';
import { EquipmentItem } from '../../types/inventory';
import { getEnergyCost, generateEquipment, calcCraftExp, getSmithingLevel, getUnlockedTier } from '../../utils/craftingLogic';
import { MATERIALS } from '../../data/materials';

const getQualityLabel = (q: number): string => {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
};

export const handleStartCrafting = (state: GameState, payload: { item: EquipmentItem }): GameState => {
    const { item } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;
    const energyCost = getEnergyCost(item, masteryCount);

    if (state.stats.energy < energyCost) return state;

    const hasResources = item.requirements.every(req => {
        const invItem = state.inventory.find(i => i.id === req.id);
        return invItem && invItem.quantity >= req.count;
    });
    if (!hasResources) return state;

    let newInventory = [...state.inventory];
    item.requirements.forEach(req => {
        newInventory = newInventory.map(invItem => {
            if (invItem.id === req.id) {
                return { ...invItem, quantity: invItem.quantity - req.count };
            }
            return invItem;
        }).filter(i => i.quantity > 0);
    });

    return {
        ...state,
        isCrafting: true,
        stats: { ...state.stats, energy: state.stats.energy - energyCost },
        inventory: newInventory,
    };
};

export const handleCancelCrafting = (state: GameState, payload: { item: EquipmentItem }): GameState => {
    const { item } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;
    const energyCost = getEnergyCost(item, masteryCount);

    let newInventory = [...state.inventory];
    item.requirements.forEach(req => {
        const existing = newInventory.find(i => i.id === req.id);
        if (existing) {
            newInventory = newInventory.map(i => i.id === req.id ? { ...i, quantity: i.quantity + req.count } : i);
        } else {
            const itemDef = Object.values(MATERIALS).find(m => m.id === req.id);
            if (itemDef) {
                newInventory.push({ ...itemDef, quantity: req.count } as InventoryItem);
            }
        }
    });

    return {
        ...state,
        isCrafting: false,
        stats: { ...state.stats, energy: state.stats.energy + energyCost },
        inventory: newInventory,
        logs: [`Cancelled work on ${item.name}. Materials restored.`, ...state.logs]
    };
};

export const handleFinishCrafting = (state: GameState, payload: { item: EquipmentItem; quality: number; bonus?: number; masteryGain?: number }): GameState => {
    const { item, quality, bonus = 0, masteryGain = 1 } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;
    const isFirstCraft = masteryCount === 0;

    // Calculate EXP - 퀄리티 수치를 직접 전달
    const expGain = calcCraftExp({
        tier: item.tier,
        quality01: quality / 100,
        isQuickCraft: masteryGain < 1.0,
        isFirstCraft,
        quality: quality
    });

    const isForge = item.craftingType === 'FORGE';
    const oldExp = isForge ? state.stats.smithingExp : state.stats.workbenchExp;
    const newExp = oldExp + expGain;

    const oldLevel = getSmithingLevel(oldExp);
    const newLevel = getSmithingLevel(newExp);
    const oldTier = getUnlockedTier(oldLevel);
    const newTier = getUnlockedTier(newLevel);

    const equipment = generateEquipment(item, quality, masteryCount, bonus);

    const newItem: InventoryItem = {
        id: equipment.id, 
        name: equipment.name,
        type: 'EQUIPMENT',
        description: item.description,
        baseValue: equipment.price,
        icon: item.icon,
        quantity: 1,
        equipmentData: equipment
    };

    const newInventory = [...state.inventory, newItem];

    const newMastery = { ...state.craftingMastery };
    newMastery[item.id] = (masteryCount || 0) + masteryGain;

    const label = getQualityLabel(quality);
    let logMsg = `Successfully crafted ${label.toLowerCase()} quality ${item.name}! (+${expGain} XP)`;
    if (bonus > 0) logMsg += ` Pinned technique applied +${bonus} enhancements.`;
    if (newLevel > oldLevel) logMsg += ` Level Up! (Lv.${newLevel})`;

    let newUnlockedTabs = [...state.unlockedTabs];
    if (!newUnlockedTabs.includes('INVENTORY')) {
        newUnlockedTabs.push('INVENTORY');
        logMsg = "Facility restored: Inventory tracking is now active. " + logMsg;
    }

    return {
        ...state,
        isCrafting: false,
        inventory: newInventory,
        unlockedTabs: newUnlockedTabs,
        craftingMastery: newMastery,
        lastCraftedItem: newItem, 
        stats: {
            ...state.stats,
            smithingExp: isForge ? newExp : state.stats.smithingExp,
            workbenchExp: !isForge ? newExp : state.stats.workbenchExp
        },
        unlockedTierPopup: newTier > oldTier ? { type: item.craftingType, tier: newTier } : state.unlockedTierPopup,
        logs: [logMsg, ...state.logs]
    };
};

export const handleSetCrafting = (state: GameState, isCrafting: boolean): GameState => {
    return { ...state, isCrafting };
};

export const handleUpdateForgeStatus = (state: GameState, payload: { temp: number }): GameState => {
    return {
        ...state,
        forgeTemperature: payload.temp,
        lastForgeTime: Date.now()
    };
};

